/** UsptBsnsDao.insert */
insert into uspt_bsns
				(
					bsns_cd
					, stdr_bsns_cd
					, bsns_nm
					, bsns_year_type_cd
					, bsns_year
					, bsns_year_detail_cd
					, ecshg_instt_nm
					, ecshg_instt_cd
					, erp_cd
					, tot_bsns_pd
					, cnsrtm
					, chrg_dept_nm
					, task_type_cd
					, enabled
					, creator_id
					, created_dt
					, updater_id
					, updated_dt
				)
		select
			#{bsnsCd}
			, #{stdrBsnsCd}
			, #{bsnsNm}
			, #{bsnsYearTypeCd}
			, #{bsnsYear}
			, #{bsnsYearDetailCd}
			, #{ecshgInsttNm}
			, #{ecshgInsttCd}
			, #{erpCd}
			, #{totBsnsPd}
			, #{cnsrtm}
			, #{chrgDeptNm}
			, task_type_cd
			, true
			, #{creatorId}
			, #{createdDt}
			, #{updaterId}
			, #{updatedDt}
		from uspt_stdr_bsns
		where
			stdr_bsns_cd = #{stdrBsnsCd}

mapper.update:
/** UsptBsnsDao.update */
update uspt_bsns
set
	bsns_nm					= #{bsnsNm}
	, ecshg_instt_nm		= #{ecshgInsttNm}
	, ecshg_instt_cd		= #{ecshgInsttCd}
	, erp_cd				= #{erpCd}
	, tot_bsns_pd			= #{totBsnsPd}
	, cnsrtm				= #{cnsrtm}
	, chrg_dept_nm			= #{chrgDeptNm}
	, bsns_year_type_cd		= #{bsnsYearTypeCd}
	, bsns_year				= #{bsnsYear}
	, bsns_year_detail_cd	= #{bsnsYearDetailCd}
	, updater_id			= #{updaterId}
	, updated_dt			= #{updatedDt}
where
	bsns_cd = #{bsnsCd}

/** UsptBsnsDao.updateTaskType */
update uspt_bsns
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, task_type_cd	= #{taskTypeCd}
where
	bsns_cd = #{bsnsCd}

/** UsptBsnsDao.updateUnable */
update uspt_bsns
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, enabled		= false
where
	bsns_cd = #{bsnsCd}

mapper.select:
/** UsptBsnsDao.selectBsnsNmList */ select bsns_cd , bsns_nm from uspt_bsns where enabled = true
and bsns_year = #{bsnsYear}
order by bsns_cd desc
